import { getArgsFromUrl } from '@badam/common-utils'

/* eslint-disable import/prefer-default-export */
const targetVersoin = 10291

function versionToNumber(versionString: string) {
  const parts = versionString.split('.')

  // 确保至少有三位
  while (parts.length < 3) {
    parts.push('0')
  }

  let result = ''
  for (let i = 0; i < 3; i += 1) {
    let currentPart = parts[i]

    if (i > 0 && currentPart.length < 2) {
      currentPart = currentPart.padStart(2, '0')
    }

    result += currentPart
  }

  return parseInt(result, 10)
}

export function isTargetVersion() {
  try {
    const versionCode = getArgsFromUrl('version_code')
    // const versionStr =
    //   Object.prototype.toString.call(versionCode) === '[object Array]'
    //     ? versionCode[0]
    //     : versionCode
    // const v = versionStr.split('.').join('')
    const version = versionToNumber(versionCode)
    return version >= targetVersoin
  } catch (e) {
    return false
  }
}

type Params = {
  login_type: 'facebook' | 'google' | 'apple'
  user_id?: string // facebook、apple必填
  access_token?: string // facebook、apple必填
  id_token?: string // google必填
}

export function callbackToClient(p: Params) {
  const ticket = encodeURIComponent(JSON.stringify(p))
  location.href = `sawaludo://sawaksa_login_key?ticket=${ticket}`
}

export function goToMobileWebview() {
  location.hash = 'mobile'
  try {
    location.href = `sawaludo://sawaksa_login_mobile?url=${encodeURIComponent(location.href)}`
  } catch (e) {
    //
  }
  location.hash = ''
}
